INSERT INTO `achievement_locale` (`ID`, `locale`, `Description_lang`, `Title_lang`, `Reward_lang`, `VerifiedBuild`) VALUES
(62773, 'deDE', 'Schließt jeden der unten aufgelisteten Abgrundfischenerfolge ab.', 'Abgrundfischen: Jejus neuer Rivale', '', 67186),
(61883, 'deDE', 'Übersteht die erste Minute eines Dekorationsduells, ohne gefangen zu werden (x3).', 'Jetzt sehr Ihr mich nicht...', '', 67186),
(61887, 'deDE', 'Schließt alle Erfolge des Dekorationsduells ab.', 'Verkleidet bis über beide Ohren', '', 67186),
(61886, 'deDE', 'Erhaltet im Dekorationsduell Zugriff auf alle Setverbesserungen.', 'Mit allem drum und dran', '', 67186),
(61882, 'deDE', 'Werdet im Dekorationsduell erfolgreich den \"gefunden\"-Status los, ohne gefangen zu werden.', 'Gefunden und entwunden', '', 67186),
(61881, 'deDE', 'Bleibt im Dekorationsduell bis zum Schluss versteckt.', 'Versteckt und unentdeckt', '', 67186),
(61880, 'deDE', 'Versteckt Euch im Dekorationsduell und bleibt eineinhalb Minuten am Stück unentdeckt.', 'Es ist kalt hier im Schatten', '', 67186),
(61879, 'deDE', 'Gewinnt im Dekorationsduell eine Runde als Sucher, nachdem alle Versteckten innerhalb von zwei Minuten gefangen wurden.', 'Erwischt!', '', 67186),
(61878, 'deDE', 'Fangt erfolgreich gegnerische Spielercharaktere als arkaner Waldläufer im Dekorationsduell.', 'Markiert und anvisiert', '', 67186),
(61793, 'deDE', 'Fangt erfolgreich gegnerische Spielercharaktere als Nullifizierer im Dekorationsduell.', 'Zur Ehre der Leere', '', 67186),
(61792, 'deDE', 'Fangt erfolgreich gegnerische Spielercharaktere als Zauberbrecher im Dekorationsduell.', 'Schnappt Euch die Zauber!', '', 67186),
(63263, 'deDE', '', '[DNT]Midnight Keystone Myth: Season One Personal Achievement', '', 67186),
(63097, 'deDE', 'Erhaltet eine Wertung für Mythisch+ von mindestens 3.400 in Saison 1 von Midnight.', 'Schlüsselsteinmythos von Midnight: Saison 1', 'Titel: Der/Die Schattenstreiter(in) & Gegenstand: Zeitverlorener Sattel', 67186),
(61594, 'deDE', 'Schließt den Schlüsselsteindungeon Himmelsnadel als Regionsbester ab.', 'Schlüsselsteinsieger: Himmelsnadel', '', 67186),
(61593, 'deDE', 'Schließt den Schlüsselsteindungeon Sitz des Triumvirats als Regionsbester ab.', 'Schlüsselsteinsieger: Sitz des Triumvirats', '', 67186),
(61592, 'deDE', 'Schließt den Schlüsselsteindungeon Die Grube von Saron als Regionsbester ab.', 'Schlüsselsteinsieger: Die Grube von Saron', '', 67186),
(61591, 'deDE', 'Schließt den Schlüsselsteindungeon Akademie von Algeth\'ar als Regionsbester ab.', 'Schlüsselsteinsieger: Akademie von Algeth\'ar', '', 67186),
(61590, 'deDE', 'Schließt den Schlüsselsteindungeon Windläuferturm als Regionsbester ab.', 'Schlüsselsteinsieger: Windläuferturm', '', 67186),
(61589, 'deDE', 'Schließt den Schlüsselsteindungeon Nexuspunkt Xenas als Regionsbester ab.', 'Schlüsselsteinsieger: Nexuspunkt Xenas', '', 67186),
(61588, 'deDE', 'Schließt den Schlüsselsteindungeon Maisarakavernen als Regionsbester ab.', 'Schlüsselsteinsieger: Maisarakavernen', '', 67186),
(61587, 'deDE', 'Schließt den Schlüsselsteindungeon Terrasse der Magister (Midnight) als Regionsbester ab.', 'Schlüsselsteinsieger: Terrasse der Magister (Midnight)', '', 67186),
(61259, 'deDE', 'Beendet Saison 1 von Mythisch+ von Midnight in den Top 0,1% aller Spieler in Eurer Region.', 'Schattenheld: Saison 1 von Midnight', 'Titel: Der/Die Schattenheld(in)', 67186),
(61253, 'deDE', 'Schließt in Saison 1 von Midnight alle Dungeons auf Mythisch+ und der Schlüsselsteinstufe 30 innerhalb des Zeitlimits ab.', 'Saison 1 von Midnight: Abgehärteter Schlüsselstein Stufe 30', 'Schlüsselsteine werden während Saison 1 von Midnight nicht mehr unter Stufe 30 abfallen.', 67186),
(61252, 'deDE', 'Schließt in Saison 1 von Midnight alle Dungeons auf Mythisch+ und der Schlüsselsteinstufe 29 innerhalb des Zeitlimits ab.', 'Saison 1 von Midnight: Abgehärteter Schlüsselstein Stufe 29', 'Schlüsselsteine werden während Saison 1 von Midnight nicht mehr unter Stufe 29 abfallen.', 67186),
