(61235, 'deDE', 'Schließt in Saison 1 von Midnight alle Dungeons auf Mythisch+ und der Schlüsselsteinstufe 13 innerhalb des Zeitlimits ab.', 'Saison 1 von Midnight: Abgehärteter Schlüsselstein Stufe 13', 'Schlüsselsteine werden während Saison 1 von Midnight nicht mehr unter Stufe 13 abfallen.', 67186),
(61233, 'deDE', 'Schließt in Saison 1 von Midnight alle Dungeons auf Mythisch+ und der Schlüsselsteinstufe 12 innerhalb des Zeitlimits ab.', 'Saison 1 von Midnight: Abgehärteter Schlüsselstein Stufe 12', 'Schlüsselsteine werden während Saison 1 von Midnight nicht mehr unter Stufe 12 abfallen.', 67186),
(12009, 'deDE', 'Bezwingt L\'ura im Sitz des Triumvirats auf dem Schwierigkeitsgrad \'Mythisch\', während alle Gruppenmitglieder unter dem Einfluss von \'Erdrückende Dunkelheit\' stehen.', 'Im Dunkeln ist gut munkeln', '', 67186),
(12005, 'deDE', 'Lasst Dunkelzahn im Sitz des Triumvirats auf dem Schwierigkeitsgrad \'Mythisch\' mit \'Schattenhaftes Anspringen\' 4 versiegelte Leerenspeicher zerstören und besiegt dann Saprish.', 'Punktlandung', '', 67186),
(12004, 'deDE', 'Zwingt Urjad mit \'Leerenriss\' aus dem Reich der Leere und bezwingt dann ihn und Zuraal den Aufgestiegenen im Sitz des Triumvirats auf dem Schwierigkeitsgrad \'Mythisch\'.', 'Leer ausgegangen', '', 67186),
(9036, 'deDE', 'Bezwingt die Oberste Weise Viryx auf der Himmelsnadel auf dem Schwierigkeitsgrad \'Heroisch\', ohne dabei eines der Schildkonstrukte zu töten.', 'Monomanie', '', 67186),
(9035, 'deDE', 'Veranlasst während der Begegnung mit Rukhran in der Himmelsnadel auf dem Schwierigkeitsgrad \'Heroisch\' drei Aschehaufen dazu, gleichzeitig Sonnenvögel zu formen.', 'Ich sah Solis', '', 67186),
(9034, 'deDE', 'Bezwingt das machterfüllte Konstrukt in der Himmelsnadel auf dem Schwierigkeitsgrad \'Heroisch\'.', 'Was guckst du?', '', 67186),
(9033, 'deDE', 'Bezwingt Ranjit auf dem Schwierigkeitsgrad \'Heroisch\' auf der Himmelsnadel, ohne dabei Schaden durch eine der folgenden Fähigkeiten zu erleiden: \'Wirbelnde Klinge\', \'Windwall\', \'Vier Winde\', \'Lichtreflex\'', 'Allzeit schlachtzugsbereit IV', '', 67186),
(4525, 'deDE', 'Räumt den Gang vor Geißelfürst Tyrannus in der Grube von Saron auf dem Schwierigkeitsgrad \'Heroisch\' beim ersten Versuch leer, ohne dass jemand Schaden durch fallende Eiszapfen erleidet.', 'Nicht nach oben sehen', '', 67186),
(4524, 'deDE', 'Bezwingt Schmiedemeister Garfrost in der Grube von Saron auf dem Schwierigkeitsgrad \'Heroisch\', bevor ein Spieler mehr als 11 Stapel von \'Permafrost\' hat.', 'Elfer raus!', '', 67186),
(62814, 'deDE', '', '', '', 67186),
(62813, 'deDE', '', '', '', 67186),
(62812, 'deDE', '', '', '', 67186),
(62811, 'deDE', '', '', '', 67186),
(62296, 'deDE', '', 'Morgenlichtwappen der Mythen verdient', '', 67186),
(42769, 'deDE', 'Wachst in Saison 1 von Midnight aus den Morgenlichtwappen des Helden heraus.', 'Held der Morgendämmerung', 'Charakterfreischaltung: Tauscht Morgenlichtwappen des Helden gegen Morgenlichtwappen der Mythen ein', 67186);
