INSERT INTO `currency_types_locale` (`ID`, `locale`, `Name_lang`, `Description_lang`, `VerifiedBuild`) VALUES
(3513, 'deDE', 'Nebulöser Leerenkern', 'Kann beim Sieg über starke Gegner in Schlachtzügen von Saison 1 von Midnight, beim Abschluss von Dungeons auf Mythisch+ oder großzügigen Tiefen und Beutejagden auf dem Schwierigkeitsgrad \'Alptraum\' in mächtige Ausrüstung umgewandelt werden.', 67186),
(3347, 'deDE', 'Morgenlichtwappen der Mythen', 'Wird verwendet, um mythische Ausrüstung der Saison 1 von Midnight auf die Gegenstandsstufen 276-289 aufzuwerten.\n\nIm Falle der Herstellung von Gegenständen wird die Stufe des hergestellten Gegenstands je nach Qualität auf 272-285 gesetzt.\n\nWird durch die folgenden Aktivitäten verdient:\n\n- Leerenspitze, Traumriss, Marsch auf Quel\'Danas (Mythisch)\n- Mythische Schlüsselsteindungeons (+9 und höher)', 67186),
(3346, 'deDE', 'Morgenlichtwappen des Helden', 'Wird verwendet, um Heldenausrüstung der Saison 1 von Midnight auf die Gegenstandsstufen 263-276 aufzuwerten. Wird durch die folgenden Aktivitäten verdient:\n\n- Leerenspitze, Traumriss, Marsch auf Quel\'Danas (Heroisch)\n- Mythische Schlüsselsteindungeons von +4 bis +8\n- Tiefen (Stufe 11)\n- Belohnung des Schatzsuchers (Stufe 8 und höher)\n- Beutejagden (Alptraum)', 67186),
(3345, 'deDE', 'Morgenlichtwappen des Helden', 'Wird verwendet, um Heldenausrüstung der Saison 1 von Midnight auf die Gegenstandsstufen 263-276 aufzuwerten.\n\nIm Falle der Herstellung von Gegenständen wird die Stufe des hergestellten Gegenstands je nach Qualität auf 259-272 gesetzt.\n\nWird durch die folgenden Aktivitäten verdient:\n\n- Leerenspitze, Traumriss, Marsch auf Quel\'Danas (Heroisch)\n- Mythische Schlüsselsteindungeons von +4 bis +8\n- Tiefen (Stufe 11)\n- Belohnung des Schatzsuchers (Stufe 8 und höher)\n- Beutejagden (Alptraum)', 67186),
(3344, 'deDE', 'Morgenlichtwappen des Champions', 'Wird verwendet, um Championausrüstung der Saison 1 von Midnight auf die Gegenstandsstufen 250-263 aufzuwerten. Wird durch die folgenden Aktivitäten verdient:\n\n- Wöchentliche Aktivitäten in der Außenwelt\n- Leerenspitze, Traumriss, Marsch auf Quel\'Danas (Normal)\n- Mythische Saisondungeons\n- Mythische Schlüsselsteindungeons von +2 bis +3\n- Tiefen (Stufen 7 bis 10)\n- Belohnung des Schatzsuchers (Stufen 6 bis 7)\n- Beutejagden (Alptraum)', 67186),
(3343, 'deDE', 'Morgenlichtwappen des Champions', 'Wird verwendet, um Championausrüstung der Saison 1 von Midnight auf die Gegenstandsstufen 250-263 aufzuwerten. Wird durch die folgenden Aktivitäten verdient:\n\n- Wöchentliche Aktivitäten in der Außenwelt\n- Leerenspitze, Traumriss, Marsch auf Quel\'Danas (Normal)\n- Mythische Saisondungeons\n- Mythische Schlüsselsteindungeons von +2 bis +3\n- Tiefen (Stufen 7 bis 10)\n- Belohnung des Schatzsuchers (Stufen 6 bis 7)\n- Beutejagden (Alptraum)', 67186),
(3342, 'deDE', 'Morgenlichtwappen des Veteranen', 'Wird verwendet, um Veteranenausrüstung der Saison 1 von Midnight auf die Gegenstandsstufen 237-250 aufzuwerten. Wird durch die folgenden Aktivitäten verdient:\n\n- Wiederholbare Aktivitäten in der Außenwelt\n- Leerenspitze, Traumriss, Marsch auf Quel\'Danas (Schlachtzugsbrowser)\n- Heroische Saisondungeons\n- Tiefen (Stufen 5 bis 6)\n- Belohnung des Schatzsuchers (Stufen 4 bis 5)\n- Beutejagden (Schwer)', 67186),
(3341, 'deDE', 'Morgenlichtwappen des Veteranen', 'Wird verwendet, um Veteranenausrüstung der Saison 1 von Midnight auf die Gegenstandsstufen 237-250 aufzuwerten.\n\nIm Falle der Herstellung von Gegenständen wird die Stufe des hergestellten Gegenstands je nach Qualität auf 233-246 gesetzt.\n\nWird durch die folgenden Aktivitäten verdient:\n\n- Wiederholbare Aktivitäten in der Außenwelt\n- Leerenspitze, Traumriss, Marsch auf Quel\'Danas (Schlachtzugsbrowser)\n- Heroische Saisondungeons\n- Tiefen (Stufen 5 bis 6)\n- Belohnung des Schatzsuchers (Stufen 4 bis 5)\n- Beutejagden (Schwer)', 67186),
(3418, 'deDE', 'Nebulöser Leerenkern', 'Kann beim Sieg über starke Gegner in Schlachtzügen von Saison 1 von Midnight, beim Abschluss von Dungeons auf Mythisch+ oder großzügigen Tiefen und Beutejagden auf dem Schwierigkeitsgrad \'Alptraum\' in mächtige Ausrüstung umgewandelt werden.', 67186),
(3391, 'deDE', 'Morgenlichtwappen des Abenteurers', 'Wird verwendet, um Abenteurerausrüstung der Saison 1 von Midnight auf die Gegenstandsstufen 224-237 aufzuwerten. Wird durch die folgenden Aktivitäten verdient:\n\n- Wiederholbare Aktivitäten in der Außenwelt\n- Tiefen (Stufe 4)\n- Beutejagden (Normal)', 67186),
(3383, 'deDE', 'Morgenlichtwappen des Abenteurers', 'Wird verwendet, um Abenteurerausrüstung der Saison 1 von Midnight auf die Gegenstandsstufen 224-237 aufzuwerten.\n\nIm Falle der Herstellung von Gegenständen wird die Stufe des hergestellten Gegenstands je nach Qualität auf 220-233 gesetzt.\n\nWird durch die folgenden Aktivitäten verdient:\n\nWiederholbare Aktivitäten in der Außenwelt\n- Tiefen (Stufe 4)\n- Beutejagden (Normal)', 67186),
(3348, 'deDE', 'Morgenlichtwappen der Mythen', 'Wird verwendet, um mythische Ausrüstung der Saison 1 von Midnight auf die Gegenstandsstufen 276-289 aufzuwerten. Wird durch die folgenden Aktivitäten verdient:\n\n- Leerenspitze, Traumriss, Marsch auf Quel\'Danas (Heroisch)\n- Mythische Schlüsselsteindungeons (+9 und höher)', 67186);
