(263286, 'deDE', '', '', '', '', 'Umfunktionierter Gong der Fungianer', 67186),
(273307, 'deDE', 'Von einem unerschrockenen Unternehmer frisch gepresst! Sie glitzert vor Zuckerkristallen... oder doch eher Manakristallen?', '', '', '', 'Phiole mit unerschrockener Limonade', 67186),
(265790, 'deDE', 'Ein Säckchen mit 10 Morgenlichtwappen des Helden und Morgenlichtwappen der Mythen.', '', '', '', 'Morgenlichtwappenvorrat', 67186),
(246753, 'deDE', '', '', '', '', 'Glorreiche Sammlung mit Morgenlichtwappen der Mythen', 67186),
(255627, 'deDE', '', '', '', '', 'Hammer des galaktischen Gladiators', 67186),
(266969, 'deDE', '', '', '', '', 'Ensemble: Gewänder des Tieftauchers', 67186),
(253582, 'deDE', '', '', '', '', 'Fangflossenflegel', 67186);
INSERT INTO `journal_encounter_section_locale` (`ID`, `locale`, `Title_lang`, `BodyText_lang`, `VerifiedBuild`) VALUES
(32672, 'deDE', 'Tanks', '$bullet; Der Hortraffer bedient sich während |cFF2959D3|Hspell:1235072|h[Einfallsreiche Maßnahmen]|h|r am nächsten Reservenhaufen.\n$bullet; Verrottete Pilze übertragen bei Kontakt |cFF2959D3|Hspell:1234846|h[Toxische Sporen]|h|r, was eine |cFF2959D3|Hspell:1245593|h[Faulige Explosion]|h|r verhindert.\n$bullet; |cFF2959D3|Hspell:1234681|h[Rasendes Gebrüll]|h|r und |cFF2959D3|Hspell:1235125|h[Herzhaftes Brüllen]|h|r fügen allen Spielercharakteren hohen Schaden zu.', 67186),
(32669, 'deDE', 'Übersicht', 'Der Hortraffer versucht, seine Reserven mit allen Mitteln gegen Plünderer zu verteidigen, und ergreift beim Erreichen von 90%, 60% und 30% Gesundheit jeweils |cFF2959D3|Hspell:1235072|h[Einfallsreiche Maßnahmen]|h|r, wodurch er eine seiner Fähigkeiten ermächtigt.\n\nBeim Erreichen von 100 Energie wirft er |cFF2959D3|Hspell:1234233|h[Verdorbene Vorräte]|h|r in die Arena, die im Verlauf von 12 Sek. verrottete Pilze entstehen lassen. Bei Berührung belegen diese Ziele mit |cFF2959D3|Hspell:1234846|h[Toxischen Sporen]|h|r, was den Pilz zerstört und die |cFF2959D3|Hspell:1245593|h[Faulige Explosion]|h|r verhindert.', 67186),
(31527, 'deDE', 'Verbotene Fracht', 'Eine Lieferung, die vor neugierigen Blicken geschützt werden soll. Bietet eine hervorragende Gelegenheit, in Deckung zu gehen.', 67186),
(31282, 'deDE', 'Tank', '$bullet; Kystia lässt Knurps mit Hilfe der |cFF2959D3|Hspell:1230289|h[Schwarzinfusion]|h|r den Spielercharakteren gegenüber feindlich werden.\n$bullet; Weicht Knurps\' |cFF2959D3|Hspell:1253811|h[Teufelsgischt]|h|r aus.\n$bullet; Unterbrecht Kystias |cFF2959D3|Hspell:1264095|h[Spiegelbilder]|h|r.', 67186),
(31281, 'deDE', 'Heiler', '$bullet; Kystia lässt Knurps mit Hilfe der |cFF2959D3|Hspell:1230289|h[Schwarzinfusion]|h|r den Spielercharakteren gegenüber feindlich werden.\n$bullet; Weicht Knurps\' |cFF2959D3|Hspell:1253811|h[Teufelsgischt]|h|r aus.\n$bullet; Kystia fügt allen Spielercharakteren schweren Schaden zu, während sie |cFF2959D3|Hspell:1265412|h[Destabilisiert]|h|r ist.', 67186),
(31280, 'deDE', 'Schadensklassen', '$bullet; Kystia lässt Knurps mit Hilfe der |cFF2959D3|Hspell:1230289|h[Schwarzinfusion]|h|r den Spielercharakteren gegenüber feindlich werden.\n$bullet; Weicht Knurps\' |cFF2959D3|Hspell:1253811|h[Teufelsgischt]|h|r aus.\n$bullet; Unterbrecht Kystias |cFF2959D3|Hspell:1264095|h[Spiegelbilder]|h|r.', 67186),
(35862, 'deDE', 'Section 18', '', 67186),
(35353, 'deDE', 'Abschnitt 17', '|n\nBy speaking with Lindormi near The Timeways portal or at the end of a Keystone Dungeon, characters with a tank specialization can enable |cFF2959D3|Hspell:1295986|h[Lindormi\'s Glow]|h|r when |cFF2959D3|Hspell:1278156|h[Lindormi\'s Guidance]|h|r is inactive.', 67186),
(34751, 'deDE', 'Abschnitt 17', '', 67186),
(34733, 'deDE', 'Xal\'ataths List', 'Xal\'atath betrügt Spielercharaktere und erklärt ihre Geschäfte für ungültig, während Todesfälle 15 Sekunden von der verbleibenden Zeit abziehen.', 67186),
(34732, 'deDE', 'Verstärkt', 'Normale Gegner haben 20% mehr Gesundheit und verursachen bis zu 20% mehr Schaden.', 67186),
(34731, 'deDE', 'Tyrannisch', 'Bosse haben 25% mehr Gesundheit. Bosse und ihre Diener verursachen bis zu 15% mehr Schaden.', 67186),
(34730, 'deDE', 'Tyrannisch und gestärkt', 'Diese Affixe stärken Gegner in mythischen Schlüsselsteindungeons weiter. Eines wird auf der mythischen Stufe 7 aktiv, das andere auf der mythischen Stufe 10. Rotiert wöchentlich.', 67186),
(34727, 'deDE', 'Xal\'ataths Handel: Verschlingen', '', 67186),
(34725, 'deDE', 'Xal\'ataths Handel: Leerengebunden', '', 67186),
(34722, 'deDE', 'Xal\'ataths Handel: Pulsare', '', 67186),
(34720, 'deDE', 'Mythische Stufe 6', '$bullet;|cFF2959D3|Hspell:1284818|h[Lindormis Rat]|h|r wurde entfernt.\n\nCharaktere mit einer Tankspezialisierung können in der Nähe des Portals zu den Zeitwegen oder am Ende eines Schlüsselsteindungeons mit Lindormi sprechen, um |cFF2959D3|Hspell:1295986|h[Lindormis Leuchten]|h|r zu erhalten, wodurch gegnerische Streitkräfte weiterhin hervorgehoben werden.', 67186),
(35809, 'deDE', 'Section 158', '', 67186),
(35491, 'deDE', 'Abschnitt 69', '', 67186),
(35490, 'deDE', 'Abschnitt 70', '', 67186),
(35489, 'deDE', 'Abschnitt 76', '', 67186),
