INSERT INTO `mail_template_locale` (`ID`, `locale`, `Body_lang`, `VerifiedBuild`) VALUES
(659, 'deDE', 'Grüße, $gAkolyth:Akolythin;!\n\nBestaunt die Wunder dieser Welt mit GLORREICHEM ÜBERFLUSS! Er wogt, er schwillt, er widersetzt sich jeder Eindämmung!\n\nEure Hingabe für meine Heiligkeit verdient eine kleine Aufmerksamkeit. Dieses Mal in Form von ungetrübtem Überfluss!\n\nUnd denkt daran, $gedler Akolyth:edle Akolythin;: Gewisse Gaben, wie verschmolzene Vitalität, werden jetzt bei anderen Händlern erscheinen. Vielleicht begegnet Ihr ihnen, sollten Eure Eskapaden Euch je in die Nähe der Tiefen von Zul\'Aman führen.\n\nMögt Ihr eine reiche Ernte einholen.\n\n- Dundun, Loa des Überflusses', 67186);
