INSERT INTO `trait_definition_locale` (`ID`, `locale`, `OverrideName_lang`, `OverrideSubtext_lang`, `OverrideDescription_lang`, `VerifiedBuild`) VALUES
(137688, 'deDE', 'Minutiöse Mehrfachherstellung', '', 'Verbessert Eure Verzauberungsmatrizen, wodurch sich die Wahrscheinlichkeit erhöht, bei der Herstellung von Illusionen oder verbrauchbaren Gegenständen zusätzliche Gegenstände zu erhalten. Außerdem erhaltet Ihr pro Punkt in dieser Spezialisierung +$ev1 $en1.', 67186),
(137685, 'deDE', '', '', 'Mehrfachherstellung gewährt bis zu +$ev1% zusätzliche Güter bei der Herstellung von verbrauchbaren Gegenständen.', 67186),
(137681, 'deDE', '', '', 'Mehrfachherstellung gewährt bis zu +$ev1% zusätzliche Güter bei der Herstellung von verbrauchbaren Gegenständen.', 67186),
(133669, 'deDE', '', '', 'Erhaltet +$ev1 $en1 bei der Herstellung von Legierungen.|n|nSchaltet die Fähigkeit frei, bei der Herstellung von Legierungen Fertigungsreagenzien einzusetzen.', 67186);
